import{_ as t,c as o,o as a,a1 as r}from"./chunks/framework.9hXSu8bi.js";const s="/mypatterndocs/static/%E9%A2%84%E8%AD%A6%E7%AD%96%E7%95%A5%E4%BB%8B%E7%BB%8D.DCPOs3D8.png",u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"zh/帮助文档/功能介绍/预警策略.md","filePath":"zh/帮助文档/功能介绍/预警策略.md"}'),e={name:"zh/帮助文档/功能介绍/预警策略.md"},n=r('<h2 id="预警策略" tabindex="-1">预警策略 <a class="header-anchor" href="#预警策略" aria-label="Permalink to &quot;预警策略&quot;">​</a></h2><blockquote><p>预警策略页面用于配置子项目的预警规则，包括预警算法类型、预警等级、预警点配置等功能。</p></blockquote><p><img src="'+s+'" alt="" data-fancybox="gallery"></p><h3 id="_1-预警策略基本信息" tabindex="-1">1. 预警策略基本信息 <a class="header-anchor" href="#_1-预警策略基本信息" aria-label="Permalink to &quot;1. 预警策略基本信息&quot;">​</a></h3><ul><li><strong>子项目名称</strong>：显示该预警策略所关联的子项目名称。</li><li><strong>预警设置状态</strong>：当前预警策略的启用状态，分为“启用”和“禁用”。</li><li><strong>预警类型</strong>：触发预警的类型，如曲线预警或图像预警。</li><li><strong>面积阈值</strong>（单位：平方米）：当形变面积超过设定值时触发预警。</li><li><strong>预警间隔</strong>（单位：小时）：在设置的间隔时间内，同一视图预警区域内、同一级别的预警不会重复触发（仅适用于 2-4 级）。若本次预警等级提升，系统将立即触发新的预警，并从该时刻重新计时。</li><li><strong>最高等级预警值差</strong>（单位：mm）：触发新的 1 级预警时，需要当前 1 级预警值与上一次 1 级预警值的差值超过该字段所设置的阈值。</li><li><strong>预警条件</strong>：预警触发的具体条件描述，分为“位移”和“速度”。</li></ul><h3 id="_2-编辑预警策略" tabindex="-1">2. 编辑预警策略 <a class="header-anchor" href="#_2-编辑预警策略" aria-label="Permalink to &quot;2. 编辑预警策略&quot;">​</a></h3><ul><li><strong>编辑</strong>：修改预警策略的各项参数配置。</li><li><strong>启用</strong>：开启或关闭该预警策略。</li><li><strong>配置等级</strong>：设置不同预警等级（如蓝色、黄色、橙色、红色）的阈值范围，也可以设置正向和负向。</li><li><strong>预警点配置</strong>：指定该预警策略应用于哪些监测点或监测面。</li></ul>',7),l=[n];function i(_,c,g,d,h,p){return a(),o("div",null,l)}const f=t(e,[["render",i]]);export{u as __pageData,f as default};
